import React from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { AuthProvider, useAuth } from './context/AuthContext';
import { CartProvider } from './context/CartContext';

// Importación de componentes
import Header from './components/Header';
import Login from './components/Login';
import Home from './components/Home'; // Asegúrate de que la ruta sea correcta
import VistaCliente from './components/VistaCliente';
import DashboardVendedor from './components/DashboardVendedor';
import Registro from './components/Registro';
import Carrito from './components/Carrito';
import MisPedidosCliente from './components/MisPedidosCliente';

const PrivateRoute = ({ children, roleRequired }) => {
    const { user, isAuthenticated, loading } = useAuth();

    if (loading) return (
        <div style={{ display: 'flex', justifyContent: 'center', marginTop: '50px', fontFamily: 'sans-serif' }}>
            <div style={{ textAlign: 'center' }}>
                <p>Cargando sesión...</p>
            </div>
        </div>
    );

    if (!isAuthenticated) return <Navigate to="/login" />;

    if (roleRequired && user?.rol !== roleRequired) {
        return <Navigate to="/" />;
    }

    return children;
};

const AppRoutes = () => {
    const { user, isAuthenticated } = useAuth();

    return (
        <>
            <Header /> 

            <Routes>
                {/* --- RUTA RAÍZ: Ahora es el Home --- */}
                <Route 
                    path="/" 
                    element={<Home isLoggedIn={isAuthenticated} userRole={user?.rol} />} 
                />

                {/* --- RUTAS PÚBLICAS --- */}
                <Route 
                    path="/login" 
                    element={!isAuthenticated ? <Login /> : <Navigate to="/" />} 
                />
                <Route path="/registro" element={<Registro />} />

                {/* --- RUTAS VENDEDOR --- */}
                <Route path="/dashboard" element={
                    <PrivateRoute roleRequired="vendedor">
                        <DashboardVendedor />
                    </PrivateRoute>
                } />

                {/* --- RUTAS CLIENTE --- */}
                <Route path="/panel-cliente" element={
                    <PrivateRoute roleRequired="cliente">
                        <VistaCliente />
                    </PrivateRoute>
                } />
                <Route path="/carrito" element={
                    <PrivateRoute roleRequired="cliente">
                        <Carrito />
                    </PrivateRoute>
                } />
                <Route path="/mis-pedidos" element={
                    <PrivateRoute roleRequired="cliente">
                        <MisPedidosCliente />
                    </PrivateRoute>
                } />

                <Route path="*" element={<Navigate to="/" />} />
            </Routes>
        </>
    );
};

function App() {
    return (
        <AuthProvider>
            <CartProvider>
                <Router>
                    <div style={{ minHeight: '100vh', background: '#f8fafc' }}>
                        <AppRoutes />
                    </div>
                </Router>
            </CartProvider>
        </AuthProvider>
    );
}

export default App;
